const autumn = require('autumn-js');

/**
 * Middleware to require premium access using Autumn feature gating
 */
const requirePremium = async (req, res, next) => {
  const customerId = req.headers['x-customer-id'];

  if (!customerId) {
    return res.status(400).json({ "error": "Missing customer ID" });
  }

  try {
    const result = await autumn.customers.check({
      customerId,
      featureId: 'premium-dashboard'
    });

    if (result.allowed) {
      return next();
    } else {
      return res.status(403).json({ "error": "Premium plan required" });
    }
  } catch (error) {
    console.error('Autumn check error:', error);
    return res.status(500).json({ "error": "Feature check failed" });
  }
};

module.exports = {
  requirePremium
};

